+fn normalized_series_rows(series: &Series) -> Vec<String> {
+    let mut rows: Vec<_> = series
+        .index()
+        .labels()
+        .iter()
+        .zip(series.values().iter())
+        .map(|(label, value)| format!("{label:?}=>{value:?}"))
+        .collect();
+    rows.sort_unstable();
+    rows
+}
